import React from 'react';
import Header from './components/Header';
import SplitBanner from './components/SplitBanner';
import TheEditSection from './components/TheEditSection';
import MensEditSection from './components/MensEditSection';
import CollabBanner from './components/CollabBanner';
import EyewearEditSection from './components/EyewearEditSection';

// ─── 이미지 교체 방법 ────────────────────────────────────────────
// 1. src/assets/images/ 폴더에 이미지 파일을 넣는다
// 2. 아래처럼 import한다
// import womenLeft  from './assets/images/hero-women-left.jpg';
// import womenRight from './assets/images/hero-women-right.jpg';
// import mensLeft   from './assets/images/hero-mens-left.jpg';
// import mensRight  from './assets/images/hero-mens-right.jpg';
// 3. SplitBanner의 leftImg / rightImg prop에 넣는다
// ────────────────────────────────────────────────────────────────

const womenProducts = [
  {
    id: 1,
    name: 'SINGULAR TOTE PIN (BLACK)',
    price: '325,000 KRW',
    bg: '#d0cec8',
    imgBg: '#b8b5ae',
    // imageUrl: productTote,  ← 이미지 import 후 여기에 추가
    showHover: false,
  },
  {
    id: 2,
    name: 'DRAPE DETAIL SUIT JACKET (IVORY)',
    price: '321,000 KRW',
    bg: '#e8e5de',
    imgBg: '#f0ede6',
    // imageUrl: productJacket,
    showHover: false,
  },
  {
    id: 3,
    name: 'OPEN BACK HIGH NECK DRESS (BLACK)',
    price: '295,000 KRW',
    bg: '#d8d5ce',
    imgBg: '#c8c5be',
    // imageUrl: productDress,
    showHover: true,  // ← 호버 시 상품명 + 가격 표시
  },
];

function App() {
  return (
    <div className="app">
      <Header />
      <main>

        {/* ── 섹션 1: Womenswear 배너 ── */}
        <SplitBanner
          year="2026"
          title="Spring Summer Womenswear Collection"
          theme="light"
          leftBg="#c8c5bc"
          rightBg="#e0ddd6"
          // leftImg={womenLeft}
          // rightImg={womenRight}
          viewStyle="box"
        />

        {/* ── THE EDIT (여성) ── */}
        <TheEditSection products={womenProducts} />

        {/* ── 섹션 2: Menswear 배너 ── */}
        <SplitBanner
          year="2026"
          title="Spring Summer Menswear Collection"
          theme="dark"
          leftBg="#2e2c2a"
          rightBg="#3a3835"
          // leftImg={mensLeft}
          // rightImg={mensRight}
          viewStyle="underline"
        />

        {/* ── THE EDIT (남성) ── */}
        <MensEditSection />

        {/* ── 섹션 3: EFFECTOR × RECTO 콜라보 배너 ── */}
        <CollabBanner />

        {/* ── THE EDIT (아이웨어) ── */}
        <EyewearEditSection />

      </main>
    </div>
  );
}

export default App;
